/* ── Page chrome mimicking github.com ─────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; }

body {
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", "Noto Sans",
               Helvetica, Arial, sans-serif, "Apple Color Emoji",
               "Segoe UI Emoji";
  font-size: 16px;
  line-height: 1.5;
  color: #1f2328;
  background-color: #ffffff;
  margin: 0;
  padding: 0;
}

/* Top breadcrumb bar */
.gh-header {
  background: #f6f8fa;
  border-bottom: 1px solid #d0d7de;
  padding: 8px 16px;
  font-size: 13px;
  color: #57606a;
}
.gh-header a {
  color: #0969da;
  text-decoration: none;
  font-weight: 600;
}
.gh-header a:hover { text-decoration: underline; }
.gh-header .sep { margin: 0 4px; color: #57606a; }

/* Centered content area, exactly as GitHub renders READMEs */
.gh-content {
  max-width: 1012px;
  margin: 0 auto;
  padding: 32px 16px;
}

/* The rendered markdown box */
.gh-box {
  border: 1px solid #d0d7de;
  border-radius: 6px;
  overflow: hidden;
}

.gh-box-header {
  background: #f6f8fa;
  border-bottom: 1px solid #d0d7de;
  padding: 8px 16px;
  font-size: 14px;
  font-weight: 600;
  color: #1f2328;
  display: flex;
  align-items: center;
  gap: 6px;
}

.gh-box-header .icon {
  color: #57606a;
}

/* Override markdown-body padding to fit inside box */
.gh-box .markdown-body {
  padding: 32px 40px 24px;
}

@media (max-width: 767px) {
  .gh-box .markdown-body { padding: 16px; }
  .gh-content { padding: 16px 12px; }
}

/* ── Syntax highlighting fixes ──────────────────────────────────────── */
/* Ensure code blocks have the right background, matching GitHub exactly */
.markdown-body pre {
  background-color: #f6f8fa;
  border-radius: 6px;
}

.markdown-body pre code.hljs {
  background: transparent;
  padding: 0;
  font-size: 85%;
}

/* Inline code — GitHub uses a reddish tint */
.markdown-body code:not(pre code) {
  background-color: #f6f8fa;
  border-radius: 6px;
  font-size: 85%;
  padding: 0.2em 0.4em;
}

/* ── KaTeX display math centering ──────────────────────────────────── */
.katex-display {
  overflow-x: auto;
  overflow-y: hidden;
  padding: 4px 0;
}

/* ── Table improvements ─────────────────────────────────────────────── */
.markdown-body table {
  display: block;
  width: max-content;
  max-width: 100%;
  overflow: auto;
}

/* ── Footer ─────────────────────────────────────────────────────────── */
.gh-footer {
  text-align: center;
  padding: 24px 16px;
  font-size: 12px;
  color: #57606a;
}
.gh-footer a { color: #57606a; }

